def write(path: str, content: str) -> None:
    target = ROOT / path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content.strip() + "\n", encoding="utf-8", newline="\n")
    print(f"wrote: {path}")


def append_once(path: str, marker: str, content: str) -> None:
    target = ROOT / path
    target.parent.mkdir(parents=True, exist_ok=True)
    existing = target.read_text(encoding="utf-8") if target.exists() else ""
    if marker in existing:
        print(f"already updated: {path}")
        return
    if existing and not existing.endswith("\n"):
        existing += "\n"
    target.write_text(existing + "\n" + content.strip() + "\n", encoding="utf-8", newline="\n")
    print(f"updated: {path}")


def main() -> None:
    for path, content in FILES.items():
        write(path, content)
    append_once("CLEANUP_BEFORE_RELEASE.md", "Cleanup reminder: MLOps model answer package", CLEANUP_APPEND)
    print("\nApplied MLOps evidence-pack model answer package.")


if __name__ == "__main__":
    main()
